export function getCurriculumLessonById(lessonId: string): CurriculumLesson | undefined {
  return curriculumLessons.find(lesson => lesson.id === lessonId);
}

export function getCurriculumLessonsByGrade(grade: string): CurriculumLesson[] {
  return curriculumLessons.filter(lesson => lesson.grade === grade);
}

export function getCurriculumLessonSetsByGrade(grade: string): string[] {
  return Array.from(
    new Set(
      curriculumLessons
        .filter(lesson => lesson.grade === grade)
        .map(lesson => lesson.set)
        .filter((value): value is string => Boolean(value)),
    ),
  );
}

export function getCurriculumLessonsByGradeAndSet(grade: string, set: string): CurriculumLesson[] {
  return curriculumLessons.filter(lesson => lesson.grade === grade && lesson.set === set);
}
